select.where:
 and ct.coupon_type = #{couponType}
 and ct.denomination = #{denomination}
 and ct.full_money = #{fullMoney}
 and ct.total_count = #{totalCount}
 and ct.receive_count = #{receiveCount}
 and ct.valid_days = #{validDays}
 and ct.start_time = #{startTime}
 and ct.end_time = #{endTime}
 and ct.scope_type = #{scopeType}
 and ct.status = #{status}
and ct.del_flag = '0'
